 margin: 0 auto;\n            padding: 0 24px;\n        }\n.approach-header {\n            text-align: center;\n            margin-bottom: 60px;\n        }\n.approach-header h2 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 36px;\n            color: #fff;\n            margin-bottom: 16px;\n        }\n.approach-header p {\n            font-size: 18px;\n            color: rgba(255,255,255,0.75);\n        }\n.approach-steps {\n            display: grid;\n            grid-template-columns: repeat(3, 1fr);\n            gap: 32px;\n        }\n.approach-step {\n            text-align: center;\n        }\n.approach-step-number {\n            width: 56px;\n            height: 56px;\n            background: linear-gradient(135deg, #00AFF0, #003CC8);\n            border-radius: 50%;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 24px;\n            font-weight: 700;\n            color: #fff;\n            margin: 0 auto 20px;\n        }\n.approach-step h3 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 20px;\n            color: #fff;\n            margin-bottom: 12px;\n        }\n.approach-step p {\n            font-size: 15px;\n            color: rgba(255,255,255,0.75);\n            line-height: 1.6;\n        }\n@media (max-width: 1024px) {\n            .industries-hero h1 { font-size: 40px; }\n            .context-stats { grid-template-columns: repeat(2, 1fr); }\n            .industry-card { grid-template-columns: 1fr; }\n            .industry-card:nth-child(even) { direction: ltr; }\n            .challenges-grid { grid-template-columns: repeat(2, 1fr); }\n            .approach-steps { grid-template-columns: 1fr; gap: 40px; }\n        }\n/* === CTA: พูดคุยเรื่องโรงงานของคุณ === */\n.ind-cta-section{background:linear-gradient(135deg, #00AFF0 0%, #003CC8 100%);padding:100px 24px;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.ind-cta-section::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg width=\'20\' height=\'20\' viewBox=\'0 0 20 20\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cpath d=\'M10 0v20M0 10h20\' stroke=\'%23fff\' stroke-width=\'0.5\' opacity=\'0.05\'/%3E%3C/svg%3E");pointer-events:none;z-index:1}\n.ind-cta-section::after{content:\'\';position:absolute;bottom:-20%;right:-10%;width:80%;height:80%;background:radial-gradient(ellipse at center,rgba(255,255,255,0.1) 0%,transparent 70%);pointer-events:none;z-index:1}\n.ind-cta-super-d{position:absolute;top:auto;right:-10%;bottom:-20%;left:auto;width:60%;min-height:60vh;background:url("data:image/svg+xml;base64,") no-repeat center bottom;background-size:contain;opacity:0.1;pointer-events:none;z-index:0}\n.ind-cta-wave-flow{position:absolute;bottom:0;left:0;right:0;height:160px;background:linear-gradient(180deg,transparent,rgba(0,60,200,0.15));opacity:0.3;z-index:1;pointer-events:none}\n.ind-cta-container{position:relative;z-index:3;max-width:700px;margin:0 auto;text-align:center}\n.ind-cta-title{font-family:\'Noto Sans\',sans-serif;font-weight:700;font-size:40px;color:#fff;line-height:1.6;margin:0 0 16px}\n.ind-cta-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:20px;color:rgba(255,255,255,0.9);margin:0 0 40px}\n/* Divi overrides — ensure font properties survive Divi cascade */\n.et_pb_section .ind-cta-title{font-weight:700 !important;font-size:40px !important;line-height:1.6 !important;color:#fff !important}\n.et_pb_section .ind-cta-subtitle{font-weight:400 !important;padding-bottom:0 !important}\n.et_pb_section .ind-cta-container p{padding-bottom:0 !important}\n\n.ind-cta-btn{font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;padding:16px 32px;border-radius:8px;cursor:pointer;transition:all 0.3s ease;text-decoration:none;display:inline-flex;align-items:center;gap:8px;position:relative;overflow:hidden;border:none;line-height:1.6}\n.ind-cta-btn::before{content:\'\';position:absolute;top:0;left:-100%;width:100%;height:100%;background:linear-gradient(90deg,transparent,rgba(255,255,255,0.2),transparent);transition:left 0.5s}\n.ind-cta-btn:hover::before{left:100%}\n.ind-cta-btn--primary{background:#fff;color:#003CC8;font-weight:600;box-shadow:0 4px 20px rgba(0,0,0,0.15)}\n.ind-cta-btn--primary:hover{transform:translateY(-3px);box-shadow:0 12px 40px rgba(0,0,0,0.2)}\n.ind-cta-btn--ghost{background:transparent;color:#fff;border:2px solid rgba(255,255,255,0.6)}\n.ind-cta-btn--ghost:hover{background:rgba(255,255,255,0.15);border-color:#fff}\n.ind-cta-btn-row{display:flex;gap:20px;flex-wrap:wrap;justify-content:center;position:relative;z-index:2}\n.ind-cta-btn{position:static;overflow:visible;display:inline-flex;align-items:center;gap:8px;padding:16px 32px;border-radius:8px;line-height:1.6}\n@media(max-width:767px){\n  .ind-cta-title{font-size:28px;margin-bottom:16px}\n  .ind-cta-subtitle{font-size:16px;margin-bottom:32px}\n  .ind-cta-btn-row{flex-direction:column;align-items:stretch;gap:16px}\n  .ind-cta-btn{width:100%;max-width:300px;margin:0 auto;text-align:center}\n}\n@media(prefers-reduced-motion:reduce){.ind-cta-btn{transition:none !important}.ind-cta-btn::before{display:none}}\n\n/* === THAI TYPOGRAPHY === */\n/* Font loaded via <link> in header — do NOT use @import here (invalid after rules) */\n\n/* Thai font stack for all body text */\nbody, .et_pb_section, .et_pb_code, .et_pb_code_inner {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n}\n\n/* Thai-specific line heights (Thai script is taller — needs !important to override Divi) */\np, li, .et_pb_text_inner { line-height: 1.8 !important; }\nh1, h2, h3, h4, h5, h6 { line-height: 1.4 !important; }\n\n/* Thai label override: JetBrains Mono doesn\'t have Thai glyphs.\n   letter-spacing breaks Thai script (chars within words must stay connected).\n   text-transform:uppercase is meaningless for Thai. */\n[class*="-label"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n/* Also fix any monospace elements that might contain Thai text */\n[class*="-source"], [class*="-company"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="industries-hero">\n    <div class="dw-d-bg dw-d-bg--center dw-d-bg--particle dw-d-parallax" style="opacity: 0.10;"></div>\n            <div class="industries-hero-inner">\n                <div class="industries-hero-badge">\n                    <span>ระบบ ERP เฉพาะทางสำหรับอุตสาหกรรมการผลิต</span>\n                </div>\n                <h1>สร้างมาเพื่ออุตสาหกรรมของคุณ<br><span>พิสูจน์แล้วจากประสบการณ์จริง</span></h1>\n                <p class="industries-hero-subtitle">โรงงานของคุณไม่ใช่โรงงานทั่วไป—ระบบ ERP ของคุณก็ไม่ควรเป็นเช่นนั้น ตั้งแต่การจัดตาราง JIT สำหรับยานยนต์ ไปจนถึงการตรวจสอบย้อนกลับชิ้นส่วนอิเล็กทรอนิกส์ และการเพิ่มประสิทธิภาพ Yield สำหรับงานโลหะ เรามีประสบการณ์ <span class="dw-years">44</span> ปีในการแก้ปัญหาเฉพาะทางบนพื้นที่หน้างาน</p>\n                <div class="industries-hero-stats">\n                    <div class="industries-hero-stat">\n                        <div class="industries-hero-stat-number">3</div>\n                        <div class="industries-hero-stat-label">อุตสาหกรรมหลัก</div>\n                    </div>\n                    <div class="industries-hero-stat">\n                        <div class="industries-hero-stat-number">100+</div>\n                        <div class="industries-hero-stat-label">ติดตั้งในประเทศไทย</div>\n                    </div>\n                    <div class="industries-hero-stat">\n                        <div class="industries-hero-stat-number dw-years">44</div>\n                        <div class="industries-hero-stat-label">ปีเชี่ยวชาญด้านการผลิต</div>\n                    </div>\n                </div>\n            </div>\n    <script>(function(){var y=new Date().getFullYear();document.querySelectorAll(\'.dw-years\').forEach(function(e){e.textContent=y-1982})})();</script>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Context"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Context: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Context: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="context-section">\n    <div class="context-inner">\n                <p class="context-label">บริบทตลาด</p>\n                <div class="context-header">\n                    <h2>ประเทศไทย: ศูนย์กลางการผลิตของอาเซียน</h2>\n                    <p>ระบบนิเวศอุตสาหกรรมที่เติบโตที่สุดในภูมิภาค พร้อมห่วงโซ่อุปทานที่ลึกซึ้งและลูกค้าระดับโลกที่มีมาตรฐานสูง</p>\n                </div>\n                <div class="context-stats">\n                    <div class="context-stat">\n                        <div class="context-stat-value">#1</div>\n                        <div class="context-stat-label">ผลิตรถยนต์อันดับ 1 อาเซียน</div>\n                    </div>\n                    <div class="context-stat">\n                        <div class="context-stat-value">2,500+</div>\n                        <div class="context-stat-label">ผู้ผลิตชิ้นส่วนยานยนต์</div>\n                    </div>\n                    <div class="context-stat">\n                        <div class="context-stat-value">$40B</div>\n                        <div class="context-stat-label">มูลค่าส่งออกอิเล็กทรอนิกส์</div>\n                    </div>\n                    <div class="context-stat">\n                        <div class="context-stat-value">~27%</div>\n                        <div class="context-stat-label">GDP จากภาคการผลิต</div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","c