ss="industry-cards">\n                    \n                    <a href="industries/automotive.html" class="industry-card">\n                        <div class="industry-card-visual">\n                            <div class="industry-card-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M7 17a2 2 0 1 0 0-4 2 2 0 0 0 0 4zM17 17a2 2 0 1 0 0-4 2 2 0 0 0 0 4z"/><path d="M5 15H3V9l2-4h10l4 4v6h-2"/><path d="M9 15h6"/><path d="M5 9h14"/></svg></div>\n                            <div class="industry-card-stat">\n                                <div class="industry-card-stat-value">500+</div>\n                                <div class="industry-card-stat-label">ซัพพลายเออร์ Tier 1-3 ที่ให้บริการ</div>\n                            </div>\n                        </div>\n                        <div class="industry-card-content">\n                            <h3 class="industry-card-title">การผลิตชิ้นส่วนยานยนต์</h3>\n                            <p class="industry-card-desc">ประเทศไทยคือ Detroit ของอาเซียน เราเข้าใจสิ่งที่ OEM ระดับ Tier-1 ต้องการ: การตรวจสอบย้อนกลับระดับ Lot ที่สมบูรณ์แบบ ตารางส่งมอบแบบ JIT และการเชื่อมต่อ EDI ที่ใช้งานได้จริงกับระบบของลูกค้า</p>\n                            <div class="industry-features">\n                                <div class="industry-feature"><svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg><span>เชื่อมต่อ EDI กับ OEM</span></div>\n                                <div class="industry-feature"><svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg><span>รองรับมาตรฐาน IATF 16949</span></div>\n                                <div class="industry-feature"><svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg><span>ตรวจสอบย้อนกลับระดับ Lot</span></div>\n                                <div class="industry-feature"><svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg><span>ระบบ Kanban และ JIT</span></div>\n                            </div>\n                            <span class="industry-card-link">สำรวจโซลูชันยานยนต์ <span>→</span></span>\n                        </div>\n                    </a>\n\n                    <a href="industries/electronics.html" class="industry-card">\n                        <div class="industry-card-visual">\n                            <div class="industry-card-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><rect x="2" y="3" width="20" height="14" rx="2" ry="2"/><line x1="8" y1="21" x2="16" y2="21"/><line x1="12" y1="17" x2="12" y2="21"/></svg></div>\n                            <div class="industry-card-stat">\n                                <div class="industry-card-stat-value">1000+</div>\n                                <div class="industry-card-stat-label">ประเภทชิ้นส่วนที่ติดตาม</div>\n                            </div>\n                        </div>\n                        <div class="industry-card-content">\n                            <h3 class="industry-card-title">การประกอบอิเล็กทรอนิกส์</h3>\n                            <p class="industry-card-desc">ผลิตหลายรุ่น ปริมาณน้อย วงจรผลิตภัณฑ์เร็ว ชิ้นส่วนนับพันต่อบอร์ด ชิ้นส่วนไวต่อความชื้น (MSD) เราสร้างระบบ MES (ระบบบริหารการผลิต) มาเพื่อรองรับความซับซ้อนนี้โดยเฉพาะ</p>\n                            <div class="industry-features">\n                                <div class="industry-feature"><svg aria-hidden="true" viewBox="0 0 20 20" fill="currentCol