วิเคราะห์ของเสีย</span></div>\n                                <div class="industry-feature"><svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg><span>เพิ่มประสิทธิภาพรอบการผลิต</span></div>\n                            </div>\n                            <span class="industry-card-link">สำรวจโซลูชันโลหะและพลาสติก <span>→</span></span>\n                        </div>\n                    </a>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Challenges"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Challenges: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Challenges: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="challenges-section">\n    <div class="dw-section-scene">\n                <svg aria-hidden="true" viewBox="0 0 1400 900" fill="none" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="xMidYMid slice">\n                    <line x1="0" y1="200" x2="450" y2="200" stroke="#000864" stroke-width="1.5" opacity="0.12"/>\n                    <line x1="550" y1="200" x2="900" y2="200" stroke="#000864" stroke-width="1.5" stroke-dasharray="8 6" opacity="0.1"/>\n                    <line x1="1000" y1="200" x2="1400" y2="200" stroke="#000864" stroke-width="1.5" opacity="0.12"/>\n                    <line x1="0" y1="500" x2="400" y2="500" stroke="#000864" stroke-width="1.5" opacity="0.12"/>\n                    <line x1="500" y1="500" x2="800" y2="500" stroke="#000864" stroke-width="1.5" stroke-dasharray="8 6" opacity="0.1"/>\n                    <line x1="900" y1="500" x2="1400" y2="500" stroke="#000864" stroke-width="1.5" opacity="0.12"/>\n                    <line x1="350" y1="0" x2="350" y2="300" stroke="#000864" stroke-width="1" opacity="0.08"/>\n                    <line x1="350" y1="380" x2="350" y2="600" stroke="#000864" stroke-width="1" stroke-dasharray="6 4" opacity="0.06"/>\n                    <line x1="1050" y1="100" x2="1050" y2="400" stroke="#000864" stroke-width="1" opacity="0.08"/>\n                    <line x1="1050" y1="500" x2="1050" y2="900" stroke="#000864" stroke-width="1" stroke-dasharray="6 4" opacity="0.06"/>\n                    <g opacity="0.5"><line x1="485" y1="190" x2="505" y2="210" stroke="#00AFF0" stroke-width="2"/><line x1="505" y1="190" x2="485" y2="210" stroke="#00AFF0" stroke-width="2"/></g>\n                    <g opacity="0.4"><line x1="435" y1="490" x2="455" y2="510" stroke="#00AFF0" stroke-width="2"/><line x1="455" y1="490" x2="435" y2="510" stroke="#00AFF0" stroke-width="2"/></g>\n                    <rect x="150" y="300" width="80" height="60" rx="4" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.1"/>\n                    <rect x="800" y="600" width="80" height="60" rx="4" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.1"/>\n                    <text x="600" y="400" font-family="\'Noto Sans\',sans-serif" font-size="32" font-weight="800" fill="#000864" opacity="0.05">?</text>\n                    <circle cx="250" cy="700" r="3" fill="#000864" opacity="0.08"/>\n                    <circle cx="700" cy="300" r="4" fill="#00AFF0" opacity="0.08"/>\n                    <circle cx="1200" cy="700" r="3" fill="#000864" opacity="0.06"/>\n                </svg>\n            </div>\n            <div class="challenges-inner" style="position: relative; z-index: 2;">\n                <div class="challenges-header">\n                    <h2>ความสามารถข้ามอุตสาหกรรม</h2>\n                    <p>ไม่ว่าคุณจะอยู่ในอุตสาหกรรมใด พื้นฐานการผลิตเหล่านี้ถูกสร้างไว้ในทุกโซลูชัน DigiWin</p>\n                </div>\n                <div class="challenges-grid">\n                    \n                    <div class="challenge-card">\n                        <div class="challenge-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg></div>\n                        <h3>ตรวจสอบย้อนกลับครบวงจร</h3>\n                        <p>ติดตามระดับ Lot ตั้งแต่วัตถุดิบจนถึงสินค้าสำเร็จรูป ตอบคำถามจากลูกค้าได้ภายในไม่กี่นาที ไม่ใช่หลายวัน</p>\n                    </div>\n                    <div class="challenge-card">\n                        <div class="challenge-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M9 5H7a2 2 0 0 0-2 2v12a2 2 0 0 0 2 2h10a2 2 0 0 0 2-2V7a2 2 0 0 0-2-2h-2"/><rect x="9" y="3" width="6" height="4" rx="2"/><path d="M9 14l2 2 4-4"/></svg></div>\n                        <h3>รองรับ BOI</h3>\n                        <p>การกระทบยอดวัตถุดิบระดับใบสั่งผลิตที่ผ่านการตรวจสอบจาก BOI ลูกค้ารายหนึ่งประหยัดภาษีเพิ่มเติมได้มากกว่า 10 ล้านบาทต่อปี</p>\n                    </div>\n                    <div class="challenge-card">\n                        <div class="challenge-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M16 3h5v5"/><path d="M8 3H3v5"/><path d="M3 16v5h5"/><path d="M16 21h5v-5"/><path d="M21 3l-7 7"/><path d="M3 21l7-7"/></svg></div>\n                        <h3>แปลงหน่วยคู่</h3>\n                        <p>แสดงกิโลกรัมและจำนวนชิ้นพร้อมกันในระบบจัดซื้อ การผลิต และการขาย ไม่ต้องใช้วิธีแก้ปัญหาชั่วคราว</p>\n                    </div>\n                    <div class="challenge-card">\n                        <div class="challenge-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><circle cx="12" cy="12" r="3"/><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/></svg></div>\n                        <h3>มองเห็นสายการผลิต</h3>\n                        <p>เห็นพื้นที่หน้างานแบบ Real-time—สถานะเครื่องจักร ความคืบหน้า Work Order และ OEE (ประสิทธิผลโดยรวมของเครื่องจักร)—ไม่ใช่ Spreadsheet ของเมื่อวาน</p>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Approach"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Approach: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Approach: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="approach-section" data-particles="bold">\n    <div class="approach-inner" style="position:relative;z-index:2;">\n                <div class="approach-header">\n                    <h2>แนวทางของเรา</h2>\n                    <p>วิธีที่เราช่วยให้คุณประสบความสำเร็จ ไม่ว่าจะเริ่มจากจุดไหน</p>\n                </div>\n                <div class="approach-steps">\n                    \n                    <div class="approach-step">\n                        <div class="approach-step-number">1</div>\n                        <h3>ทำความเข้าใจ</h3>\n                        <p>เราเริ่มจากการเข้าใจปัญหาเฉพาะของคุณ—ไม่ใช่การยัดเยียดโซลูชันสำเร็จรูป ทุกโรงงานมีความแตกต่าง</p>\n                    </div>\n                    <div class="approach-step">\n                        <div class="approach-step-number">2</div>\n                        <h3>ออกแบบ</h3>\n                        <p>เราออกแบบโซลูชันที่เหมาะกับระดับความพร้อมของคุณ เริ่มจากจุดที่คุณอยู่ ไม่ใช่จุดที่ “ควรจะอยู่”</p>\n                    </div>\n                    <div class="approach-step">\n                        <div class="approach-step-number">3</div>\n                        <h3>ส่งมอบ</h3>\n                        <p>เราดำเนินการเป็นเฟส ส่งมอบคุณค่าอย่างรวดเร็ว คุณจะเห็น ROI ก่อนที่โปรเจกต์จะเสร็จสมบูรณ์</p>\n                    </div>\n                </div>\n            </div>\n    \n<script>\n(function(){\n  \'use strict\';\n  var reducedMotion=window.matchMedia(\'(prefers-reduced-motion: reduce)\').matches;\n  var PI2=Math.PI*2;\n  var BLUE=[0,175,240],CYAN=[0,230,255];\n  var PRESETS={\n    subtle:{frontOpacity:0.30,backOpacity:0.04,frontRadius:4.5,backRadius:0.6,color:BLUE,colorAlt:CYAN,altRatio:0.12},\n    medium:{frontOpacity:0.45,backOpacity:0.06,frontRadius:5.0,backRadius:0.8,color:BLUE,colorAlt:CYAN,altRatio:0.18},\n    bold:{frontOpacity:0.60,backOpacity:0.10,frontRadius:5.5,backRadius:1.0,color:CYAN,colorAlt:BLUE,altRatio:0.25}\n  };\n  function lerp(a,b,t){return a+(b-a)*t}\n  function DataOcean(el){\n    this.el=el;this.canvas=null;this.ctx=null;this.w=0;this.h=0;\n    this.dpr=Math.min(window.devicePixelRatio||1,2);this.visible=false;this.raf=null;this.time=0;this.resizeTimer=null;this.colors=null;\n    this.opts=this._parseOpts();this._setup();this._buildColors();this._observe();\n    if(!reducedMotion){this._loop()}else{this.visible=true;this._draw(0)}\n  }\n  DataOcean.prototype._parseOpts=function(){var n=this.el.getAttribute(\'data-particles\')||\'subtle\';if(n===\'\'||n===\'true\')n=\'subtle\';return PRESETS[n]||PRESETS.subtle};\n  DataOcean.prototype._setup=function(){\n    var c=document.createElement(\'canvas\');c.setAttribute(\'aria-hidden\',\'true\');\n    c.style.cssText=\'position:absolute;inset:0;width:100%;height:100%;pointer-events:none;z-index:0;\';\n    var pos=getComputedStyle(this.el).position;if(pos===\'static\')this.el.style.position=\'relative\';\n    this.el.style.overflow=\'hidden\';this.el.insertBefore(c,this.el.firstChild);this.canvas=c;this.ctx=c.getContext(\'2d\');this._resize();\n    var self=this;window.addEventListener(\'resize\',function(){clearTimeout(self.resizeTimer);self.resizeTimer=setTimeout(function(){self._resize();self._buildColors()},200)});\n  };\n  DataOcean.prototype._resize=function(){var r=this.el.getBoundingClientRect();this.w=r.width;this.h=r.height;this.canvas.width=this.w*this.dpr;this.canvas.height=this.h*this.dpr;this.ctx.setTransform(this.dpr,0,0,this.dpr,0,0)};\n  DataOcean.prototype._buildColors=function(){var cols=Math.min(65,Math.ceil(this.w/22)+4);var rows=35;this._cols=cols;this._rows=rows;var n=cols*rows;this.colors=new Array(n);var alt=this.opts.altRatio;for(var i=0;i<n;i++){this.colors[i]=Math.random()<alt?this.opts.colorAlt:this.opts.color}};\n  DataOcean.prototype._observe=function(){var self=this;if(\'IntersectionObserver\' in window){this._obs=new IntersectionObserver(function(e){self.visible=e[0].isIntersecting},{rootMargin:\'150px 0px\'});this._obs.observe(this.el)}else{this.visible=true}};\n  DataOcean.prototype._loop=function(){var self=this;var last=0;(function tick(ts){self.raf=requestAnimationFrame(tick);if(!self.visible)return;if(ts-last<30)return;last=ts;self.time+=0.006;self._draw(self.time)})(0)};\n  DataOcean.prototype._draw=function(t){\n    var ctx=this.ctx,w=this.w,h=this.h,opts=this.opts,cols=this._cols,rows=this._rows;\n    ctx.clearRect(0,0,w,h);var ground=h+10,horizon=h*0.35,totalSpan=ground-horizon,idx=0;\n    for(var row=rows-1;row>=0;row--){\n      var depth=row/(rows-1),mappedDepth=Math.pow(depth,0.55),baseY=ground-mappedDepth*totalSpan;\n      var dotR=lerp(opts.frontRadius,opts.backRadius,depth),dotA=lerp(opts.frontOpacity,opts.backOpacity,depth);\n      var colSpacing=lerp(w/(cols-4),w/(cols+15),depth),rowShift=depth*w*0.12;\n      var waveScale=1-depth*0.75,amp1=70*waveScale,amp2=25*waveScale;\n      for(var col=0;col<cols;col++){\n        var screenX=col*colSpacing-rowShift+colSpacing*0.5;\n        if(screenX<-30||screenX>w+30){idx++;continue}\n        var worldX=col*24,worldZ=row*18;\n        var wave=amp1*Math.sin(worldX*0.0065+worldZ*0.012+t*0.9);\n        wave+=amp2*Math.sin(worldX*0.013-worldZ*0.008+t*0.55+1.8);\n        var screenY=baseY-wave;if(screenY<-15||screenY>h+15){idx++;continue}\n        var c=this.colors[idx%this.colors.length];\n        ctx.beginPath();ctx.arc(screenX,screenY,dotR,0,PI2);\n        ctx.fillStyle=\'rgba(\'+c[0]+\',\'+c[1]+\',\'+c[2]+\',\'+dotA+\')\';ctx.fill();idx++;\n      }\n    }\n  };\n  DataOcean.prototype.destroy=function(){if(this.raf)cancelAnimationFrame(this.raf);if(this._obs)this._obs.disconnect();if(this.canvas&&this.canvas.parentNode)this.canvas.parentNode.removeChild(this.canvas)};\n  function init(){var els=document.querySelectorAll(\'[data-particles]\');for(var i=0;i<els.length;i++)new DataOcean(els[i])}\n  if(document.readyState===\'loading\')document.addEventListener(\'DOMContentLoaded\',init);else init();\n})();\n</script>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: พูดคุยเรื่องโรงงานของคุณ"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: พูดคุยเรื่องโรงงานของคุณ: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: พูดคุยเรื่องโรงงานของคุณ: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="ind-cta-section">\n    <div class="ind-cta-super-d" aria-hidden="true"></div>\n    <div class="ind-cta-wave-flow" aria-hidden="true"></div>\n    <div class="ind-cta-container">\n      <h2 class="ind-cta-title">พูดคุยเรื่องโรงงานของคุณ</h2>\n      <p class="ind-cta-subtitle">ทุกโรงงานมีความแตกต่าง ให้เราเข้าใจโรงงานของคุณ</p>\n      <div class="ind-cta-btn-row">\n        <a href="/th/demo/" class="ind-cta-btn ind-cta-btn--primary">ติดต่อเรา</a>\n        <a href="/products/" class="ind-cta-btn ind-cta-btn--ghost">ดูผลิตภัณฑ์</a>\n      </div>\n    </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
  post_modified = NOW(),
  post_modified_gmt = UTC_TIMESTAMP()
WHERE ID = 100781;

-- Step 2: Update Divi 5 custom CSS
DELETE FROM wp_postmeta WHERE post_id = 100781 AND meta_key = '_et_pb_custom_css';
INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100781, '_et_pb_custom_css', '/* === GLOBAL DIVI THEME RESET === */\n.et_pb_section,.et_pb_row,.et_pb_column,.et_pb_code,.et_pb_code_inner{font-family:\'Noto Sans\',sans-serif !important;font-weight:400 !important;font-size:16px !important;color:#333 !important}\n.et_pb_section h1,.et_pb_section h2,.et_pb_section h3,.et_pb_section h4,.et_pb_section h5,.et_pb_section h6{padding-bottom:0 !important}\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden !important;margin:0 !important}\n.et_pb_row:not([class*=\'tb_body\']){max-width:100% !important;width:100% !important;padding:0 !important;margin-top:0 !important;margin-bottom:0 !important;gap:0 !important}\n.et_pb_column:not([class*=\'tb_body\']){padding:0 !important;margin:0 !important;gap:0 !important}\n.et_pb_section .et_pb_row .et_pb_column .et_pb_text.et_pb_module{margin:0 !important;padding:0 !important}\n.section-title{line-height:1.6;-webkit-font-smoothing:auto}\n.section-subtitle{margin-left:auto;margin-right:auto;line-height:1.6}\n/* fade-in / scroll-fade-in: always visible (no JS scroll observer in Divi) */\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === DIVI MOBILE ROW PADDING OVERRIDE === */\n/* Divi injects: @media(max-width:640px){.et_pb_section .et_pb_row{padding:0 24px !important}}\n   Specificity 0,2,0. We use .et_pb_row.et_pb_row (0,2,0 doubled = 0,2,0 still, but\n   .et_pb_section prefix pushes us to 0,3,0) to beat it. */\n@media(max-width:640px){\n  .et_pb_section .et_pb_row.et_pb_row{padding:0 !important}\n}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* === HERO (S1) === */\n/* TODO: Review and remap class selectors to use hero prefix */\n/* TODO: Add section container: .hero-section{...;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px} */\n.industries-hero {\n            background: linear-gradient(165deg, #0f1419 0%, #1a2632 40%, #000864 100%);\n            padding: 160px 0 120px;\n            position: relative;\n            overflow: hidden;\n            min-height: 60vh;\n            display: flex;\n            align-items: center;\n        }\n.industries-hero::before {\n            content: \'\';\n            position: absolute;\n            top: 0;\n            left: 0;\n            right: 0;\n            bottom: 0;\n            background-image: url("data:image/svg+xml,%3Csvg viewBox=\'0 0 400 400\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'noiseFilter\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.9\' numOctaves=\'4\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23noiseFilter)\'/%3E%3C/svg%3E");\n            opacity: 0.03;\n            pointer-events: none;\n            animation: grain 8s steps(10) infinite;\n        }\n.industries-hero::after {\n            content: \'\';\n            position: absolute;\n            top: 0;\n            left: 0;\n            right: 0;\n            bottom: 0;\n            background: radial-gradient(ellipse at 70% 30%, rgba(0, 175, 240, 0.12) 0%, transparent 50%),\n                        radial-gradient(ellipse at 30% 80%, rgba(0, 175, 240, 0.08) 0%, transparent 40%);\n            pointer-events: none;\n        }\n.industries-hero-inner {\n            max-width: 1200px;\n            margin: 0 auto;\n            padding: 0 24px;\n            position: relative;\n            z-index: 2;\n            text-align: center;\n            animation: slide-up 0.8s ease-out;\n        }\n.industries-hero-badge {\n            display: inline-flex;\n            align-items: center;\n            gap: 10px;\n            background: rgba(0, 175, 240, 0.1);\n            border: 1px solid rgba(0, 175, 240, 0.3);\n            padding: 10px 20px;\n            border-radius: 50px;\n            color: #00AFF0;\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 11px;\n            font-weight: 500;\n            text-transform: uppercase;\n            letter-spacing: 0.1em;\n            margin-bottom: 28px;\n        }\n.industries-hero-badge::before {\n            content: \'\';\n            width: 8px;\n            height: 8px;\n            background: #00AFF0;\n            border-radius: 50%;\n            animation: pulse-dot 2s ease-in-out infinite;\n        }\n.industries-hero h1 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: clamp(40px, 5vw, 56px);\n            font-weight: 700;\n            color: #fff;\n            margin: 0 0 24px 0;\n            line-height: 1.1;\n            letter-spacing: -0.03em;\n        }\n.industries-hero h1 span {\n            color: #00AFF0;\n        }\n.industries-hero-subtitle {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 19px;\n            color: rgba(255,255,255,0.75);\n            max-width: 680px;\n            margin: 0 auto 40px;\n            line-height: 1.7;\n        }\n.industries-hero-stats {\n            display: flex;\n            gap: 48px;\n            justify-content: center;\n            padding-top: 40px;\n            border-top: 1px solid rgba(255, 255, 255, 0.1);\n        }\n.industries-hero-stat {\n            text-align: center;\n        }\n.industries-hero-stat-number {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 36px;\n            font-weight: 800;\n            color: #00AFF0;\n            letter-spacing: -0.02em;\n        }\n.industries-hero-stat-label {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 11px;\n            color: rgba(255, 255, 255, 0.75);\n            text-transform: uppercase;\n            letter-spacing: 0.1em;\n            margin-top: 6px;\n        }\n@media (max-width: 1024px) {\n            .industries-hero h1 { font-size: 40px; }\n            .context-stats { grid-template-columns: repeat(2, 1fr); }\n            .industry-card { grid-template-columns: 1fr; }\n            .industry-card:nth-child(even) { direction: ltr; }\n            .challenges-grid { grid-template-columns: repeat(2, 1fr); }\n            .approach-steps { grid-template-columns: 1fr; gap: 40px; }\n        }\n@media (prefers-reduced-motion: reduce) {\n            .industries-hero-inner,\n            .industries-hero::before,\n            .industries-hero-badge::before,\n            .context-stat,\n            .industry-card,\n            .industry-card-link,\n            .challenge-card,\n            .challenge-icon,\n            .dw-d-parallax,\n            .dw-wave-flow,\n            .dw-wave-fade,\n            .dw-d-bg {\n                animation: none !important;\n                transition: none !important;\n            }\n            .industry-card.visible {\n                opacity: 1;\n                transform: none;\n            }\n        }\n@media (max-width: 640px) {\n            .industries-hero { padding: 120px 0 80px; }\n            .industries-hero h1 { font-size: 32px; }\n            .industries-hero-subtitle { font-size: 17px; }\n            .industries-hero-stats { flex-wrap: wrap; gap: 32px; }\n            .context-stats { grid-template-columns: 1fr; }\n            .context-stat-value { font-size: 32px; }\n            .industry-card-visual { padding: 40px; }\n            .industry-card-content { padding: 32px; }\n            .industry-card-title { font-size: 24px; }\n            .industry-features { grid-template-columns: 1fr; }\n            .challenges-grid { grid-template-columns: 1fr; }\n        }\n\n@media(prefers-reduced-motion:reduce){}\n\n/* Super D decoration */\n.dw-d-bg{position:absolute;top:50%;right:-10%;left:auto;width:60%;min-height:60vh;background:url("data:image/svg+xml;base64,") no-repeat center right;background-size:contain;transform:translateY(-50%);opacity:0.2;pointer-events:none;z-index:0}\n/* === CONTEXT (S2) === */\n/* TODO: Review and remap class selectors to use con prefix */\n/* TODO: Add section container: .context-section{...;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px} */\n.context-section {\n            padding: 120px 0;\n            background: #ffffff;\n            position: relative;\n        }\n.context-section::before {\n            content: \'\';\n            position: absolute;\n            top: 0;\n            left: 0;\n            right: 0;\n            height: 1px;\n            background: linear-gradient(90deg, transparent, #00AFF0, transparent);\n        }\n.context-inner {\n            max-width: 1100px;\n            margin: 0 auto;\n            padding: 0 24px;\n        }\n.context-label {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 11px;\n            font-weight: 500;\n            color: #00AFF0;\n            text-transform: uppercase;\n            letter-spacing: 0.15em;\n            text-align: center;\n            margin-bottom: 16px;\n        }\n.context-header {\n            text-align: center;\n            margin-bottom: 60px;\n        }\n.context-header h2 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 40px;\n            font-weight: 700;\n            color: #000864;\n            margin-bottom: 16px;\n            letter-spacing: -0.02em;\n        }\n.context-header p {\n            font-size: 18px;\n            color: #5b6b80;\n            max-width: 700px;\n            margin: 0 auto;\n            line-height: 1.6;\n        }\n.context-stats {\n            display: grid;\n            grid-template-columns: repeat(4, 1fr);\n            gap: 24px;\n            margin-bottom: 60px;\n        }\n.context-stat {\n            text-align: center;\n            padding: 40px 24px;\n            background: #F5F7FA;\n            border-radius: 20px;\n            transition: all 0.4s ease;\n            border: 1px solid transparent;\n        }\n.context-stat:hover {\n            background: #ffffff;\n            border-color: rgba(0, 175, 240, 0.2);\n            box-shadow: 0 12px 40px rgba(0, 175, 240, 0.1);\n        }\n.context-stat-value {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 44px;\n            font-weight: 800;\n            color: #00AFF0;\n            line-height: 1;\n            letter-spacing: -0.02em;\n        }\n.context-stat-label {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 11px;\n            color: #5b6b80;\n            margin-top: 12px;\n            line-height: 1.4;\n            text-transform: uppercase;\n            letter-spacing: 0.05em;\n        }\n@media (max-width: 1024px) {\n            .industries-hero h1 { font-size: 40px; }\n            .context-stats { grid-template-columns: repeat(2, 1fr); }\n            .industry-card { grid-template-columns: 1fr; }\n            .industry-card:nth-child(even) { direction: ltr; }\n            .challenges-grid { grid-template-columns: repeat(2, 1fr); }\n            .approach-steps { grid-template-columns: 1fr; gap: 40px; }\n        }\n@media (prefers-reduced-motion: reduce) {\n            .industries-hero-inner,\n            .industries-hero::before,\n            .industries-hero-badge::before,\n            .context-stat,\n            .industry-card,\n            .industry-card-link,\n            .challenge-card,\n            .challenge-icon,\n            .dw-d-parallax,\n            .dw-wave-flow,\n            .dw-wave-fade,\n            .dw-d-bg {\n                animation: none !important;\n                transition: none !important;\n            }\n            .industry-card.visible {\n                opacity: 1;\n                transform: none;\n            }\n        }\n@media (max-width: 640px) {\n            .industries-hero { padding: 120px 0 80px; }\n            .industries-hero h1 { font-size: 32px; }\n            .industries-hero-subtitle { font-size: 17px; }\n            .industries-hero-stats { flex-wrap: wrap; gap: 32px; }\n            .context-stats { grid-template-columns: 1fr; }\n            .context-stat-value { font-size: 32px; }\n            .industry-card-visual { padding: 40px; }\n            .industry-card-content { padding: 32px; }\n            .industry-card-title { font-size: 24px; }\n            .industry-features { grid-template-columns: 1fr; }\n            .challenges-grid { grid-template-columns: 1fr; }\n        }\n\n.context-section{padding:100px 0;background:#fff}\n.context-inner{max-width:900px;margin:0 auto;padding:0 24px;text-align:center}\n.context-inner h2{font-family:\'Noto Sans\', sans-serif;font-size:36px;color:#000864;margin-bottom:24px}\n.context-inner p{font-size:18px;color:#5b6b80;line-height:1.8}\n.context-inner p strong{color:#000864}\n\n@media(prefers-reduced-motion:reduce){}\n\n/* Super D decoration */\n.dw-d-bg{position:absolute;top:50%;right:-10%;left:auto;width:60%;min-height:60vh;background:url("data:image/svg+xml;base64,") no-repeat center right;background-size:contain;transform:translateY(-50%);opacity:0.12;pointer-events:none;z-index:0}\n/* === SECTION (S3) === */\n/* TODO: Review and remap class selectors to use sec prefix */\n/* TODO: Add section container: .industries-section{...;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px} */\n.industries-section {\n            padding: 120px 0;\n            background: #F5F7FA;\n            position: relative;\n        }\n.industries-section::before {\n            content: \'\';\n            position: absolute;\n            top: 0;\n            left: 0;\n            right: 0;\n            bottom: 0;\n            background-image: radial-gradient(circle, rgba(0, 175, 240, 0.03) 1px, transparent 1px);\n            background-size: 30px 30px;\n            pointer-events: none;\n        }\n.industries-inner {\n            max-width: 1200px;\n            margin: 0 auto;\n            padding: 0 24px;\n            position: relative;\n            z-index: 1;\n        }\n.industries-label {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 11px;\n            font-weight: 500;\n            color: #00AFF0;\n            text-transform: uppercase;\n            letter-spacing: 0.15em;\n            text-align: center;\n            margin-bottom: 16px;\n        }\n.industries-header {\n            text-align: center;\n            margin-bottom: 72px;\n        }\n.industries-header h2 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 40px;\n            font-weight: 700;\n            color: #000864;\n            margin-bottom: 16px;\n            letter-spacing: -0.02em;\n        }\n.industries-header p {\n            font-size: 18px;\n            color: #5b6b80;\n            line-height: 1.6;\n        }\n.industry-cards {\n            display: flex;\n            flex-direction: column;\n            gap: 36px;\n        }\n.industry-card {\n            display: grid;\n            grid-template-columns: 1fr 1fr;\n            gap: 0;\n            background: #ffffff;\n            border-radius: 24px;\n            overflow: hidden;\n            box-shadow: 0 4px 24px rgba(0,0,0,0.06);\n            transition: all 0.5s cubic-bezier(0.4, 0, 0.2, 1);\n            text-decoration: none;\n            border: 1px solid #e8eef3;\n            opacity: 0;\n            transform: translateY(40px);\n        }\n.industry-card.visible {\n            opacity: 1;\n            transform: translateY(0);\n        }\n.industry-card:hover {\n            box-shadow: 0 24px 64px rgba(0, 175, 240, 0.18);\n            transform: translateY(-8px);\n            border-color: transparent;\n        }\n.industry-card:nth-child(even) {\n            direction: rtl;\n        }\n.industry-card:nth-child(even) > * {\n            direction: ltr;\n        }\n.industry-card-visual {\n            background: linear-gradient(165deg, #0f1419 0%, #1a2632 50%, #000864 100%);\n            padding: 60px;\n            display: flex;\n            flex-direction: column;\n            justify-content: center;\n            align-items: center;\n            text-align: center;\n            position: relative;\n            overflow: hidden;\n        }\n.industry-card-visual::before {\n            content: \'\';\n            position: absolute;\n            top: 0;\n            left: 0;\n            right: 0;\n            bottom: 0;\n            background-image: url("data:image/svg+xml,%3Csvg viewBox=\'0 0 400 400\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'noiseFilter\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.9\' numOctaves=\'4\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23noiseFilter)\'/%3E%3C/svg%3E");\n            opacity: 0.03;\n            pointer-events: none;\n        }\n.industry-card-icon {\n            width: 100px;\n            height: 100px;\n            background: rgba(0, 175, 240, 0.15);\n            border-radius: 24px;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            margin-bottom: 28px;\n            filter: drop-shadow(0 4px 16px rgba(0, 0, 0, 0.2));\n        }\n.industry-card-icon svg {\n            width: 52px;\n            height: 52px;\n            stroke: #fff;\n            stroke-width: 1.5;\n            fill: none;\n        }\n.industry-card-stat {\n            color: #fff;\n        }\n.industry-card-stat-value {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 52px;\n            font-weight: 800;\n            color: #00AFF0;\n            letter-spacing: -0.02em;\n        }\n.industry-card-stat-label {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 11px;\n            color: rgba(255,255,255,0.75);\n            margin-top: 8px;\n            text-transform: uppercase;\n            letter-spacing: 0.05em;\n        }\n.industry-card-content {\n            padding: 48px;\n            display: flex;\n            flex-direction: column;\n            justify-content: center;\n        }\n.industry-card-title {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 28px;\n            color: #000864;\n            margin-bottom: 16px;\n        }\n.industry-card-desc {\n            font-size: 16px;\n            color: #5b6b80;\n            line-height: 1.7;\n            margin-bottom: 24px;\n        }\n.industry-features {\n            display: grid;\n            grid-template-columns: 1fr 1fr;\n            gap: 12px;\n            margin-bottom: 24px;\n        }\n.industry-feature {\n            display: flex;\n            align-items: center;\n            gap: 8px;\n            font-size: 14px;\n            color: #475569;\n        }\n.industry-feature svg {\n            width: 16px;\n            height: 16px;\n            color: #0369a1;\n            flex-shrink: 0;\n        }\n.industry-card-link {\n            display: inline-flex;\n            align-items: center;\n            gap: 8px;\n            color: #0369a1;\n            font-family: \'Noto Sans\', sans-serif;\n            font-weight: 600;\n            font-size: 15px;\n            text-decoration: none;\n            transition: gap 0.3s ease;\n        }\n.industry-card:hover .industry-card-link {\n            gap: 12px;\n        }\n@media (max-width: 1024px) {\n            .industries-hero h1 { font-size: 40px; }\n            .context-stats { grid-template-columns: repeat(2, 1fr); }\n            .industry-card { grid-template-columns: 1fr; }\n            .industry-card:nth-child(even) { direction: ltr; }\n            .challenges-grid { grid-template-columns: repeat(2, 1fr); }\n            .approach-steps { grid-template-columns: 1fr; gap: 40px; }\n        }\n@media (prefers-reduced-motion: reduce) {\n            .industries-hero-inner,\n            .industries-hero::before,\n            .industries-hero-badge::before,\n            .context-stat,\n            .industry-card,\n            .industry-card-link,\n            .challenge-card,\n            .challenge-icon,\n            .dw-d-parallax,\n            .dw-wave-flow,\n            .dw-wave-fade,\n            .dw-d-bg {\n                animation: none !important;\n                transition: none !important;\n            }\n            .industry-card.visible {\n                opacity: 1;\n                transform: none;\n            }\n        }\n@media (max-width: 640px) {\n            .industries-hero { padding: 120px 0 80px; }\n            .industries-hero h1 { font-size: 32px; }\n            .industries-hero-subtitle { font-size: 17px; }\n            .industries-hero-stats { flex-wrap: wrap; gap: 32px; }\n            .context-stats { grid-template-columns: 1fr; }\n            .context-stat-value { font-size: 32px; }\n            .industry-card-visual { padding: 40px; }\n            .industry-card-content { padding: 32px; }\n            .industry-card-title { font-size: 24px; }\n            .industry-features { grid-template-columns: 1fr; }\n            .challenges-grid { grid-template-columns: 1fr; }\n        }\n\n/* Defensive SVG sizing */\nsvg:not([width]):not([class]){max-width:48px;max-height:48px}\n@media(prefers-reduced-motion:reduce){}\n\n/* Super D decoration */\n.dw-d-bg{position:absolute;top:50%;right:-10%;left:auto;width:60%;min-height:60vh;background:url("data:image/svg+xml;base64,") no-repeat center right;background-size:contain;transform:translateY(-50%);opacity:0.12;pointer-events:none;z-index:0}\n/* === CHALLENGES (S4) === */\n/* TODO: Review and remap class selectors to use cha prefix */\n/* TODO: Add section container: .challenges-section{...;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px} */\n.challenges-section {\n            padding: 100px 0;\n            background: #fff;\n        }\n.challenges-inner {\n            max-width: 1100px;\n            margin: 0 auto;\n            padding: 0 24px;\n        }\n.challenges-header {\n            text-align: center;\n            margin-bottom: 60px;\n        }\n.challenges-header h2 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 36px;\n            color: #000864;\n            margin-bottom: 16px;\n        }\n.challenges-header p {\n            font-size: 18px;\n            color: #5b6b80;\n        }\n.challenges-grid {\n            display: grid;\n            grid-template-columns: repeat(4, 1fr);\n            gap: 24px;\n        }\n.challenge-card {\n            background: #fff;\n            border: 1px solid #e2e8f0;\n            border-radius: 16px;\n            padding: 32px 24px;\n            text-align: center;\n            transition: all 0.3s ease;\n        }\n.challenge-card:hover {\n            border-color: #00AFF0;\n            box-shadow: 0 8px 30px rgba(0, 175, 240, 0.12);\n        }\n.challenge-icon {\n          